import { Header } from './js/Header';
import { Items } from './js/Items';
import './/App.css'
import React from 'react';
import { TodoList } from './js/TodoList';


const tasks=[
  {text: 'Revisar Examenes', completed: false},
  {text: 'Escribir', completed: true},
  {text: 'Correr', completed: true},
  {text: 'Caminar', completed: false},

]

function App() {
  return (

    <React.Fragment>
      <Header completados={10} total= {15} />


       <TodoList>
        {tasks.map(task=><Items key= {task.text}
        text={task.text}
        completed={task.completed}/>
       )}
       </TodoList>



    </React.Fragment>
  );
}


export default App;
